def test_report_style_template_audit_parsing_helpers_are_split_from_contract_facade():
    facade = BACKEND / "report_style_template_audit.py"
    helpers = BACKEND / "report_style_template_parsing.py"
    facade_text = facade.read_text(encoding="utf-8")
    facade_lines = facade_text.splitlines()

    assert helpers.exists()
    assert "import report_style_template_parsing as parsing" in facade_text
    assert "from report_style_template_parsing import" not in facade_text
    assert "def _dynamic_include_targets" not in facade_text
    assert "def _optioned_static_include_targets" not in facade_text
    assert "def _non_canonical_include_targets" not in facade_text
    assert "def _included_templates" not in facade_text
    assert "def _literal_template_output" not in facade_text
    assert "def _jinja_expressions" not in facade_text
    assert "def _jinja_block_tags" not in facade_text
    assert "_JINJA_COMMENT_RE = " not in facade_text
    assert "_CSS_TOKEN_RE = " not in facade_text
    assert len(facade_lines) < 280
    assert max(len(line) for line in facade_lines) < 91
    assert '_STYLE_LEAF_PREFIX = "report_styles"' in facade_text
    assert "leaf.startswith(_STYLE_LEAF_PREFIX)" in facade_text
    assert "_STYLE_PREFIX =" not in facade_text
    assert "leaf.startswith(_STYLE_PREFIX)" not in facade_text
    assert "_find_optioned_includes = find_optioned_active_report_style_includes" in facade_text
    assert '_ContractCheck("optioned_active_includes", _find_optioned_includes)' in facade_text
    assert "_find_missing_includes = find_missing_active_report_style_templates" in facade_text
    assert '_ContractCheck("missing_active_includes", _find_missing_includes)' in facade_text
    assert (
        '_ContractCheck("missing_active_includes", '
        "find_missing_active_report_style_templates)"
        not in facade_text
    )
    assert (
        "_find_noncanonical_tags = "
        "find_non_canonical_active_report_style_include_tags"
        in facade_text
    )
    assert (
        '_ContractCheck("non_canonical_active_include_tags", _find_noncanonical_tags)'
        in facade_text
    )
    assert "_find_non_canonical_include_tags" not in facade_text
    assert "def _existing_active_style_templates(" in facade_text
    assert "_existing_active_report_style_templates" not in facade_text
    assert "def _style_include_targets(path: Path) -> list[str]:" in facade_text
    assert "stack.extend(_style_include_targets(path))" in facade_text
    assert "_report_style_include_targets" not in facade_text
    assert len(helpers.read_text(encoding="utf-8").splitlines()) < 120
    adjacent_defs = [
        f"{line_no}: {line}"
        for line_no, line in enumerate(facade_lines, 1)
        if line.startswith(("def ", "class "))
        and line_no > 1
        and facade_lines[line_no - 2] != ""
    ]
    assert adjacent_defs == []
    registry_line = facade_lines.index("_CONTRACT_CHECKS = (")
    assert facade_lines[registry_line - 1] == ""


def test_report_style_template_audit_uses_public_parsing_api():
    facade = BACKEND / "report_style_template_audit.py"
    facade_text = facade.read_text(encoding="utf-8")
    tree = ast.parse(facade_text, filename=str(facade))

    private_imports = [
        alias.name
        for node in ast.walk(tree)
        if isinstance(node, ast.ImportFrom) and node.module == "report_style_template_parsing"
        for alias in node.names
        if alias.name.startswith("_")
    ]

    assert private_imports == []


