def test_report_style_template_css_pseudo_selector_fragment_closes_on_own_line():
    helpers = BACKEND / "report_style_template_css_tokens.py"
    helper_lines = helpers.read_text(encoding="utf-8").splitlines()

    prefix_fragment = '    rf":{{1,2}}-?{_CSS_IDENTIFIER_RE_FRAGMENT}"'
    suffix_fragment = r'    r"(?:\([^;\n{{}}]*\))?"'
    current_combined = (
        '    rf":{{1,2}}-?{_CSS_IDENTIFIER_RE_FRAGMENT}" '
        r'r"(?:\([^;\n{{}}]*\))?")'
    )
    assert prefix_fragment in helper_lines
    assert suffix_fragment in helper_lines
    assert current_combined not in helper_lines
    assert helper_lines[helper_lines.index(suffix_fragment) + 1] == ")"


