def test_report_text_safety_modules_use_shared_numeric_guard():
    modules = [
        BACKEND / "data_trust_scoring.py",
        BACKEND / "reporting" / "audit_banner.py",
        BACKEND / "reporting" / "execution_summary_values.py",
        BACKEND / "reporting" / "quant_warning.py",
        BACKEND / "reporting" / "reading_notice_values.py",
        BACKEND / "reporting" / "snapshot_integrity_notice.py",
    ]
    forbidden_fragments = (
        "def _is_non_finite",
        "def _non_finite",
        "import math",
        "from decimal import Decimal",
        "from numbers import Real",
        ".is_finite()",
    )

    for path in modules:
        text = path.read_text(encoding="utf-8")
        assert "from numeric_safety import is_non_finite_number" in text
        for fragment in forbidden_fragments:
            assert fragment not in text, f"{path.relative_to(ROOT)} still has local numeric guard: {fragment}"


