def test_structured_output_facades_keep_explicit_public_api_and_no_core_definitions():
    facade_contracts = {
        BACKEND / "structured_output_models.py": {
            "exports": {
                "STRUCTURED_AGENT_RESPONSE_SCHEMAS",
                "build_structured_output_instruction",
                "get_structured_response_schema",
                "MoatStructuredOutput",
                "PriceTargetStructuredOutput",
                "RecommendationStructuredOutput",
                "BubbleSniperStructuredOutput",
                "ManagementSentimentStructuredOutput",
                "BearAdvocateStructuredOutput",
                "SwingTradeSetup",
            },
            "forbidden_defs": {
                "AnalysisMarkdownMixin",
                "MoatScores",
                "PriceTargets",
                "RecommendationFields",
                "ConfidenceBasis",
                "ScenarioTrigger",
                "ManagementHighlight",
                "DownsideRisk",
                "DcfScenarioOutput",
            },
        },
        BACKEND / "structured_output_normalizer.py": {
            "exports": {
                "normalize_structured_output",
                "structured_output_to_report_text",
                "confidence_score",
                "price_targets_have_unit_error",
                "warn_high_confidence_with_low_trust",
            },
            "forbidden_defs": {
                "_coerce_reasoning_steps",
                "_coerce_price_target_payload",
                "_coerce_recommendation_payload",
                "_normalize_recommendation_payload_aliases",
                "structured_output_to_report_text",
                "price_targets_have_unit_error",
            },
        },
    }

    for path, contract in facade_contracts.items():
        text = path.read_text(encoding="utf-8")
        tree = ast.parse(text, filename=str(path))
        assigned_names = {
            target.id
            for node in tree.body
            if isinstance(node, ast.Assign)
            for target in node.targets
            if isinstance(target, ast.Name)
        }
        defined_names = {
            node.name
            for node in tree.body
            if isinstance(node, (ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef))
        }

        assert "__all__" in assigned_names, str(path.relative_to(ROOT))
        assert contract["exports"] <= set(getattr(__import__(path.stem), "__all__")), str(path.relative_to(ROOT))
        assert not (contract["forbidden_defs"] & defined_names), str(path.relative_to(ROOT))


def test_structured_output_internal_helpers_do_not_import_compat_facades():
    allowed_facade_consumers = {
        BACKEND / "structured_output_models.py",
        BACKEND / "structured_output_normalizer.py",
        BACKEND / "structured_output_runtime.py",
        BACKEND / "structured_outputs.py",
    }
    forbidden_facades = {"structured_output_models", "structured_output_normalizer"}
    offenders = []

    for path in BACKEND.glob("structured_output*.py"):
        if path in allowed_facade_consumers:
            continue
        tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    if alias.name.split(".", 1)[0] in forbidden_facades:
                        offenders.append(f"{path.relative_to(ROOT)} imports {alias.name}")
            elif isinstance(node, ast.ImportFrom) and node.module:
                if node.module.split(".", 1)[0] in forbidden_facades:
                    offenders.append(f"{path.relative_to(ROOT)} imports from {node.module}")

    assert offenders == []


