def test_report_base_styles_are_split_into_foundation_includes():
    entry = BACKEND / "templates" / "includes" / "report_styles_base.html.j2"
    tokens = BACKEND / "templates" / "includes" / "report_styles_tokens.html.j2"
    sidebar = BACKEND / "templates" / "includes" / "report_styles_sidebar.html.j2"
    inline = BACKEND / "templates" / "includes" / "report_styles_inline_notes.html.j2"
    entry_text = entry.read_text(encoding="utf-8")

    assert tokens.exists()
    assert sidebar.exists()
    assert inline.exists()
    assert len(entry_text.splitlines()) < 12
    assert entry_text.count("{% include") == 3
    assert '{% include "includes/report_styles_tokens.html.j2" %}' in entry_text
    assert '{% include "includes/report_styles_sidebar.html.j2" %}' in entry_text
    assert '{% include "includes/report_styles_inline_notes.html.j2" %}' in entry_text
    assert ".sidebar" not in entry_text
    assert ".source-tooltip" not in entry_text

    tokens_text = tokens.read_text(encoding="utf-8")
    assert '{% include "includes/report_styles_theme_tokens.html.j2" %}' in tokens_text
    assert '{% include "includes/report_styles_document_base.html.j2" %}' in tokens_text
    assert ":root" not in tokens_text
    assert "body {" not in tokens_text
    assert ".sidebar" not in tokens_text
    assert len(tokens_text.splitlines()) < 10

    sidebar_text = sidebar.read_text(encoding="utf-8")
    assert '{% include "includes/report_styles_sidebar_shell.html.j2" %}' in sidebar_text
    assert '{% include "includes/report_styles_sidebar_nav.html.j2" %}' in sidebar_text
    assert '{% include "includes/report_styles_sidebar_actions.html.j2" %}' in sidebar_text
    assert ".source-tooltip" not in sidebar_text
    assert ".executive-thesis" not in sidebar_text
    assert len(sidebar_text.splitlines()) < 12

    inline_text = inline.read_text(encoding="utf-8")
    assert '{% include "includes/report_styles_source_notes.html.j2" %}' in inline_text
    assert '{% include "includes/report_styles_thesis_synthesis.html.j2" %}' in inline_text
    assert ".source-citation" not in inline_text
