def test_report_source_tooltip_body_flow_style_does_not_emit_noop_display_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    flow = includes / "report_styles_source_tooltip_content_flow.html.j2"
    flow_body = includes / "report_styles_source_tooltip_content_flow_body.html.j2"

    assert 'report_styles_source_tooltip_content_flow_body.html.j2' not in flow.read_text(encoding="utf-8")
    assert "display: block" not in flow_body.read_text(encoding="utf-8")
    assert ".source-tooltip p {\n            display: block;\n        }" not in css


def test_report_source_tooltip_body_spacing_style_does_not_emit_noop_margin_css():
    from jinja2 import Environment, FileSystemLoader

