def test_report_sidebar_nav_section_title_case_transform_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    section_title_case = includes / "report_styles_sidebar_nav_section_title_case.html.j2"
    case_transform = includes / "report_styles_sidebar_nav_section_title_case_transform.html.j2"
    section_title = includes / "report_styles_sidebar_nav_section_title.html.j2"

    assert 'report_styles_sidebar_nav_section_title_case.html.j2' not in section_title.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_sidebar_nav_section_title_case_letter_spacing.html.j2' in (
        section_title.read_text(encoding="utf-8")
    )
    assert 'report_styles_sidebar_nav_section_title_case_transform.html.j2' not in (
        section_title_case.read_text(encoding="utf-8")
    )
    assert "text-transform:" not in case_transform.read_text(encoding="utf-8")
    assert ".nav-section-title {\n            text-transform: none;\n        }" not in css


