def test_report_sidebar_nav_item_cursor_style_does_not_emit_noop_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    base = includes / "report_styles_sidebar_nav_item_base.html.j2"
    interaction = includes / "report_styles_sidebar_nav_item_base_interaction.html.j2"
    cursor = includes / "report_styles_sidebar_nav_item_base_interaction_cursor.html.j2"

    assert 'report_styles_sidebar_nav_item_base_interaction.html.j2' not in base.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_sidebar_nav_item_base_interaction_cursor.html.j2' not in interaction.read_text(
        encoding="utf-8"
    )
    assert "cursor: pointer;" not in cursor.read_text(encoding="utf-8")
    assert ".nav-item {\n            cursor: pointer;\n        }" not in css


