def test_report_sidebar_disabled_states_do_not_use_global_opacity():
    includes_dir = BACKEND / "templates" / "includes"
    disabled_tone_files = {
        "report_styles_sidebar_nav_item_states_disabled_opacity.html.j2": (
            ".nav-item.is-disabled",
            "color: var(--text-muted);",
        ),
        "report_styles_sidebar_watchlist_button_disabled_opacity.html.j2": (
            ".add-to-watchlist-btn:disabled",
            "color: var(--text-muted);",
        ),
    }
    violations: list[str] = []

    for filename, (selector, color_declaration) in disabled_tone_files.items():
        path = includes_dir / filename
        text = path.read_text(encoding="utf-8")
        if selector not in text:
            violations.append(f"{filename}: missing selector {selector}")
        if color_declaration not in text:
            violations.append(f"{filename}: missing {color_declaration}")
        if "opacity:" in text:
            violations.append(f"{filename}: uses global opacity for disabled state")

    assert not violations, "\n".join(violations)


