def test_report_chart_title_case_style_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    entry = includes / "report_styles_chart_canvas_title_case_tracking.html.j2"
    case = includes / "report_styles_chart_canvas_title_case.html.j2"
    canvas = includes / "report_styles_chart_canvas.html.j2"

    assert 'report_styles_chart_canvas_title_case_tracking.html.j2' not in canvas.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_chart_canvas_title_tracking.html.j2' in canvas.read_text(encoding="utf-8")
    assert 'report_styles_chart_canvas_title_case.html.j2' not in entry.read_text(encoding="utf-8")
    assert "text-transform:" not in case.read_text(encoding="utf-8")
    assert ".chart-title {\n            text-transform: none;\n        }" not in css


