    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    entry = includes / "report_styles_price_target_text_scenario_case_tracking.html.j2"
    case = includes / "report_styles_price_target_text_scenario_case.html.j2"
    scenario = includes / "report_styles_price_target_text_scenario.html.j2"

    assert 'report_styles_price_target_text_scenario_case_tracking.html.j2' not in scenario.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_price_target_text_scenario_tracking.html.j2' in scenario.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_price_target_text_scenario_case.html.j2' not in entry.read_text(encoding="utf-8")
    assert "text-transform:" not in case.read_text(encoding="utf-8")
    assert ".pt-scenario {\n            text-transform: none;\n        }" not in css


