def test_report_trade_setup_card_direction_accent_styles_use_border_not_shadow():
    includes_dir = BACKEND / "templates" / "includes"
    accent_expectations = {
        "report_styles_trade_setup_card_direction_long_accent.html.j2": (
            ".trade-direction-long",
            "border-top: 3px solid #22c55e;",
        ),
        "report_styles_trade_setup_card_direction_short_accent.html.j2": (
            ".trade-direction-short",
            "border-top: 3px solid #ef4444;",
        ),
        "report_styles_trade_setup_card_direction_neutral_accent.html.j2": (
            ".trade-direction-neutral",
            "border-top: 3px solid #f59e0b;",
        ),
    }
    violations: list[str] = []

    for filename, (selector, declaration) in accent_expectations.items():
        path = includes_dir / filename
        text = path.read_text(encoding="utf-8")
        if selector not in text:
            violations.append(f"{filename}: missing selector {selector}")
        if declaration not in text:
            violations.append(f"{filename}: missing {declaration}")
        if "box-shadow:" in text:
            violations.append(f"{filename}: uses box-shadow for direction accent")
        if "border-color" in text:
            violations.append(f"{filename}: mixes accent with border-color")

    assert not violations, "\n".join(violations)


