def test_report_trade_setup_card_grid_spacing_reset_does_not_emit_noop_margin_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    spacing = includes / "report_styles_trade_setup_card_grid_spacing.html.j2"
    grid = includes / "report_styles_trade_setup_card_grid.html.j2"
    reset = includes / "report_styles_trade_setup_card_grid_spacing_reset.html.j2"

    assert 'report_styles_trade_setup_card_grid_spacing.html.j2' not in grid.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_trade_setup_card_grid_spacing_gap.html.j2' in grid.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_trade_setup_card_grid_spacing_reset.html.j2' not in spacing.read_text(
        encoding="utf-8"
    )
    assert "margin: 0;" not in reset.read_text(encoding="utf-8")
    assert ".trade-setup-grid {\n            margin: 0;\n        }" not in css


