def test_report_overview_cover_heading_kicker_case_style_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    kicker_case = includes / "report_styles_overview_cover_heading_kicker_case.html.j2"
    kicker_case_transform = (
        includes / "report_styles_overview_cover_heading_kicker_case_transform.html.j2"
    )
    kicker = includes / "report_styles_overview_cover_heading_kicker.html.j2"

    assert 'report_styles_overview_cover_heading_kicker_case.html.j2' not in kicker.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_overview_cover_heading_kicker_case_tracking.html.j2' in kicker.read_text(
        encoding="utf-8"
    )
    assert 'report_styles_overview_cover_heading_kicker_case_transform.html.j2' not in (
        kicker_case.read_text(encoding="utf-8")
    )
    assert "text-transform:" not in kicker_case_transform.read_text(encoding="utf-8")
    assert ".report-cover-kicker {\n            text-transform: none;\n        }" not in css


