def test_report_tear_sheet_title_case_style_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    title_case = includes / "report_styles_tear_sheet_title_case.html.j2"

    assert "text-transform:" not in title_case.read_text(encoding="utf-8")
    assert ".tear-sheet-title {\n            text-transform: none;" not in css


