def test_report_verdict_banner_label_case_style_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    label = includes / "report_styles_verdict_banner_text_label.html.j2"
    label_case = includes / "report_styles_verdict_banner_text_label_case.html.j2"

    assert 'report_styles_verdict_banner_text_label_case.html.j2' not in label.read_text(
        encoding="utf-8"
    )
    assert "text-transform:" not in label_case.read_text(encoding="utf-8")
    assert ".verdict-text .verdict-label {\n            text-transform: none;\n        }" not in css


def test_report_overview_hero_metrics_are_split_into_focused_includes():
    entry = BACKEND / "templates" / "includes" / "report_styles_overview_hero_metrics.html.j2"
    hero = BACKEND / "templates" / "includes" / "report_styles_overview_hero.html.j2"
    metrics = BACKEND / "templates" / "includes" / "report_styles_overview_metrics.html.j2"
    entry_text = entry.read_text(encoding="utf-8")

    assert hero.exists()
    assert metrics.exists()
    assert len(entry_text.splitlines()) < 10
    assert entry_text.count("{% include") == 2
    assert '{% include "includes/report_styles_overview_hero.html.j2" %}' in entry_text
    assert '{% include "includes/report_styles_overview_metrics.html.j2" %}' in entry_text
    assert ".hero-title" not in entry_text
    assert ".metrics-grid" not in entry_text

    hero_text = hero.read_text(encoding="utf-8")
