def test_report_overview_metric_label_case_style_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    label = includes / "report_styles_overview_metric_text_label.html.j2"
    label_case = includes / "report_styles_overview_metric_text_label_case.html.j2"

    assert 'report_styles_overview_metric_text_label_case.html.j2' not in label.read_text(
        encoding="utf-8"
    )
    assert "text-transform:" not in label_case.read_text(encoding="utf-8")
    assert ".metric-label {\n            text-transform: none;\n        }" not in css


def test_report_overview_metric_card_hover_interaction_animation_is_disabled():
    includes_dir = BACKEND / "templates" / "includes"
    transition = includes_dir / "report_styles_overview_metric_cards_base_transition.html.j2"
    hover = includes_dir / "report_styles_overview_metric_cards_hover.html.j2"
    hover_motion = includes_dir / "report_styles_overview_metric_cards_hover_motion.html.j2"
    transition_text = transition.read_text(encoding="utf-8")
    hover_text = hover.read_text(encoding="utf-8")
    hover_motion_text = hover_motion.read_text(encoding="utf-8")

    assert "transition:" not in transition_text
    assert "background-color 0.2s" not in transition_text
    assert "border-color 0.2s" not in transition_text
    assert "transform" not in transition_text
    assert '{% include "includes/report_styles_overview_metric_cards_hover_motion.html.j2" %}' not in hover_text
    assert ".metric-card:hover" not in hover_motion_text
    assert "transform:" not in hover_motion_text
    assert "translateY(" not in hover_motion_text


def test_report_overview_hero_styles_are_split_into_focused_includes():
    entry = BACKEND / "templates" / "includes" / "report_styles_overview_hero.html.j2"
    shell = BACKEND / "templates" / "includes" / "report_styles_overview_hero_shell.html.j2"
    content = BACKEND / "templates" / "includes" / "report_styles_overview_hero_content.html.j2"
    entry_text = entry.read_text(encoding="utf-8")

    assert shell.exists()
    assert content.exists()
