def test_report_overview_hero_background_tints_do_not_emit_noop_background_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes_dir = BACKEND / "templates" / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")
    tint_includes = [
        "report_styles_overview_hero_background_before_tint.html.j2",
        "report_styles_overview_hero_background_after_tint.html.j2",
    ]
    violations: list[str] = []

    for filename in tint_includes:
        path = includes_dir / filename
        text = path.read_text(encoding="utf-8")
        if "radial-gradient(" in text:
            violations.append(str(path.relative_to(ROOT)))
        if "background: none;" in text:
            violations.append(f"{path.relative_to(ROOT)} emits background none")
        if "background:" in text:
            violations.append(f"{path.relative_to(ROOT)} emits background")

    assert not violations, "\n".join(violations)
    assert ".hero::before {\n            background: none;\n        }" not in css
    assert ".hero::after {\n            background: none;\n        }" not in css


