def test_report_motion_styles_do_not_emit_noop_animation_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    motion = includes / "report_styles_motion.html.j2"
    reduced = includes / "report_styles_motion_reduced.html.j2"
    section = includes / "report_styles_motion_section.html.j2"
    reduced_section = includes / "report_styles_motion_reduced_section.html.j2"

    assert 'report_styles_motion_section.html.j2' not in motion.read_text(encoding="utf-8")
    assert 'report_styles_motion_reduced_section.html.j2' not in reduced.read_text(encoding="utf-8")
    assert "animation:" not in section.read_text(encoding="utf-8")
    assert "animation:" not in reduced_section.read_text(encoding="utf-8")
    assert "animation: none;" not in css
    assert ".section { animation: none; }" not in css


