def test_report_element_margin_reset_styles_do_not_emit_global_reset_duplicates():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    global_reset = includes / "report_styles_document_base_reset_margin.html.j2"
    mode_copy = includes / "report_styles_mode_template_body_grid_copy.html.j2"
    trade_title_spacing = includes / "report_styles_trade_setup_frame_heading_title_spacing.html.j2"
    trade_value_spacing = includes / "report_styles_trade_setup_card_term_value_spacing.html.j2"
    trade_catalyst_spacing = includes / "report_styles_trade_setup_catalyst_body_spacing.html.j2"

    assert "* { margin: 0; }" in global_reset.read_text(encoding="utf-8")
    for path in (mode_copy, trade_title_spacing, trade_value_spacing, trade_catalyst_spacing):
        assert "margin: 0;" not in path.read_text(encoding="utf-8")

    assert ".mode-template-body p {\n            margin: 0;\n        }" not in css
    assert ".trade-setup-header h3 {\n            margin: 0;\n        }" not in css
    assert ".trade-setup-card dd {\n            margin: 0;\n        }" not in css
    assert ".trade-catalyst p {\n            margin: 0;\n        }" not in css


