def test_report_element_padding_reset_styles_do_not_emit_global_reset_duplicates():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    global_reset = includes / "report_styles_document_base_reset_padding.html.j2"
    reading_notice_layout = includes / "report_styles_reading_notice_check_list_layout.html.j2"
    reading_notice_padding = includes / "report_styles_reading_notice_check_list_layout_padding.html.j2"
    audit_sections_list = includes / "report_styles_audit_banner_sections_list.html.j2"

    assert "* { padding: 0; }" in global_reset.read_text(encoding="utf-8")
    assert 'report_styles_reading_notice_check_list_layout_padding.html.j2' not in reading_notice_layout.read_text(
        encoding="utf-8"
    )
    assert "padding: 0;" not in reading_notice_padding.read_text(encoding="utf-8")
    assert "padding: 0;" not in audit_sections_list.read_text(encoding="utf-8")
    assert ".report-reading-notice-checks {\n            padding: 0;\n        }" not in css
    assert ".audit-section ul {\n            padding: 0;\n        }" not in css


