def test_report_reading_notice_frame_copy_kicker_casing_does_not_emit_noop_text_transform_css():
    from jinja2 import Environment, FileSystemLoader

    templates = BACKEND / "templates"
    includes = templates / "includes"
    env = Environment(loader=FileSystemLoader(str(templates)))
    css = env.get_template("includes/report_styles.html.j2").render(rec_color="#2563eb")

    kicker = includes / "report_styles_reading_notice_frame_copy_kicker.html.j2"
    kicker_casing = includes / "report_styles_reading_notice_frame_copy_kicker_casing.html.j2"

    assert 'report_styles_reading_notice_frame_copy_kicker_casing.html.j2' not in (
        kicker.read_text(encoding="utf-8")
    )
    assert "text-transform:" not in kicker_casing.read_text(encoding="utf-8")
    assert ".report-reading-notice-kicker {\n            text-transform: none;\n        }" not in css


